settings_json:
{
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "input=$(cat); case \"$input\" in *emit-skill-return*) printf '%s' \"$input\" | /hermetic/py/python -m hpc_agent._kernel.hooks.skill_return_autofetch;; esac"
          }
        ]
      },
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "input=$(cat); case \"$input\" in *block-drive*) printf '%s' \"$input\" | /hermetic/py/python -m hpc_agent._kernel.hooks.decision_rendezvous_autofetch;; esac"
          }
        ]
      },
      {
        "matcher": "AskUserQuestion",
        "hooks": [
          {
            "type": "command",
            "command": "/hermetic/py/python -m hpc_agent._kernel.hooks.answer_capture"
          }
        ]
      }
    ],
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "input=$(cat); case \"$input\" in *qsub*|*sbatch*|*qdel*|*scancel*|*qmod*|*qalter*) printf '%s' \"$input\" | /hermetic/py/python -m hpc_agent._kernel.hooks.scheduler_write_fence;; esac"
          }
        ]
      }
    ],
    "SessionStart": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "/hermetic/py/python -m hpc_agent._kernel.hooks.alert_count"
          }
        ]
      }
    ],
    "UserPromptSubmit": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "/hermetic/py/python -m hpc_agent._kernel.hooks.utterance_capture"
          }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "/hermetic/py/python -m hpc_agent._kernel.hooks.stop_multiplex hpc_agent._kernel.hooks.skill_return_stop_guard hpc_agent._kernel.hooks.decision_rendezvous_stop_guard hpc_agent._kernel.hooks.relay_audit_stop"
          }
        ]
      }
    ]
  },
  "permissions": {
    "allow": [
      "Skill(alpha)",
      "Skill(beta)"
    ],
    "deny": [
      "Bash(ssh *cluster.example.test*)",
      "Bash(scp *cluster.example.test*)"
    ]
  }
}
